    """Test a specific scenario"""
    print(f"\nTest: {name}")
    print("="*60)

    engine = Engine(
        loaders=[
            [
                'django.template.loaders.locmem.Loader',
                templates,
            ]
        ]
    )

    try:
        template = engine.get_template(final_template)
        output = template.render(Context({}))

        print(f"Output: {repr(output)}")
        print(f"Expected: {repr(expected)}")

        if output == expected:
            print("✓ PASSED")
            return True
        else:
            print("✗ FAILED")
            return False
    except Exception as e:
        print(f"✗ ERROR: {e}")
        import traceback
        traceback.print_exc()
        return False

# Test scenarios
passed = 0
failed = 0

# Scenario 1: Basic nested blocks at 3 levels
scenario1 = test_scenario(
    "Basic nested blocks at 3 levels",
    {
        "base.html": "{% block outer %}OUTER_BASE:{% block inner %}INNER_BASE{% endblock %}{% endblock %}",
        "middle.html": "{% extends 'base.html' %}{% block outer %}OUTER_MIDDLE:{% block inner %}INNER_MIDDLE{% endblock %}{% endblock %}",
        "final.html": "{% extends 'middle.html' %}{% block inner %}INNER_FINAL{% endblock %}",
    },
    "final.html",
    "OUTER_MIDDLE:INNER_FINAL"
)
if scenario1:
    passed += 1
else:
    failed += 1

# Scenario 2: Nested blocks with multiple inner blocks
scenario2 = test_scenario(
    "Multiple inner blocks",
    {
        "base.html": "{% block outer %}OUTER_BASE:{% block inner1 %}INNER1_BASE{% endblock %}+{% block inner2 %}INNER2_BASE{% endblock %}{% endblock %}",
        "middle.html": "{% extends 'base.html' %}{% block outer %}OUTER_MIDDLE:{% block inner1 %}INNER1_MIDDLE{% endblock %}+{% block inner2 %}INNER2_MIDDLE{% endblock %}{% endblock %}",
        "final.html": "{% extends 'middle.html' %}{% block inner1 %}INNER1_FINAL{% endblock %}",
    },
    "final.html",
    "OUTER_MIDDLE:INNER1_FINAL+INNER2_MIDDLE"
)
if scenario2:
    passed += 1
else:
    failed += 1

# Scenario 3: Deeply nested blocks (4 levels)
scenario3 = test_scenario(
    "Four levels of inheritance",
    {
        "base.html": "{% block a %}A_BASE:{% block b %}B_BASE:{% block c %}C_BASE{% endblock %}{% endblock %}{% endblock %}",
        "level2.html": "{% extends 'base.html' %}{% block a %}A_L2:{% block b %}B_L2:{% block c %}C_L2{% endblock %}{% endblock %}{% endblock %}",
        "level3.html": "{% extends 'level2.html' %}{% block b %}B_L3:{% block c %}C_L3{% endblock %}{% endblock %}",
        "level4.html": "{% extends 'level3.html' %}{% block c %}C_L4{% endblock %}",
    },
    "level4.html",
    "A_L2:B_L3:C_L4"
)
if scenario3:
    passed += 1
else:
    failed += 1

# Scenario 4: Nested blocks with block.super
scenario4 = test_scenario(
    "Nested blocks with block.super",
    {
        "base.html": "{% block outer %}OUTER_BASE:{% block inner %}INNER_BASE{% endblock %}{% endblock %}",
        "middle.html": "{% extends 'base.html' %}{% block outer %}OUTER_MIDDLE:{% block inner %}INNER_MIDDLE+{{ block.super }}{% endblock %}{% endblock %}",
        "final.html": "{% extends 'middle.html' %}{% block inner %}INNER_FINAL{% endblock %}",
    },
    "final.html",
    "OUTER_MIDDLE:INNER_FINAL"
)
if scenario4:
    passed += 1
else:
    failed += 1

print(f"\n{'='*60}")
print(f"Summary: {passed} passed, {failed} failed")

